12	const COMPONENT_TYPES = ["rune", "moonstone"];
13	const COMPONENT_BLOCK_SIZE = 3;
14	const COMPONENT_BLOCK_PRICE = 60;
15	const CURSED_MULTIPLIER = 1.5;
16	
17	type Item = { type: string; cursed?: boolean };
18	type Step = { op: string; items: Item[] };
19	type Scenario = { steps: Step[] };
20	
21	const baseForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;
22	
23	const applyItemModifiers = (item: Item, basePrice: number): number =>
24	  item.cursed ? basePrice * CURSED_MULTIPLIER : basePrice;
25	
26	const premiumForItem = (item: Item): number =>
27	  applyItemModifiers(item, baseForType(item.type));
28	
29	const countItemsOfType = (items: Item[], type: string): number =>
30	  items.filter((item) => item.type === type).length;
31	
32	const premiumForComponentType = (items: Item[], type: string): number => {
33	  const count = countItemsOfType(items, type);
34	  return count === COMPONENT_BLOCK_SIZE
35	    ? COMPONENT_BLOCK_PRICE
36	    : count * baseForType(type);
37	};
38	
39	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
40	
41	const basePremiumFor = (items: Item[]): number => {
42	  const componentsTotal = COMPONENT_TYPES.reduce(
43	    (sum, type) => sum + premiumForComponentType(items, type),
44	    0,
45	  );
46	  const nonComponentsTotal = items
47	    .filter((item) => !isComponent(item))
48	    .reduce((sum, item) => sum + premiumForItem(item), 0);
49	  return componentsTotal + nonComponentsTotal;
50	};
51	
52	export const runScenario = (input: unknown): { results: Array<{ premium: number }> } => {
53	  const { steps } = input as Scenario;
54	  const premium = basePremiumFor(steps[0].items) + PROCESSING_FEE;
55	  return { results: [{ premium }] };
56	};
