const CURSED_MULTIPLIER = 1.5;
const HIGH_ENCHANTMENT_MULTIPLIER = 1.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

type Item = { type: string; cursed?: boolean; enchantment?: number };
type Step = { op: string; items: Item[] };
type Scenario = { steps: Step[] };

const baseForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;

const applyItemModifiers = (item: Item, basePrice: number): number => {
  if (item.cursed) return basePrice * CURSED_MULTIPLIER;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD)
    return basePrice * HIGH_ENCHANTMENT_MULTIPLIER;
  return basePrice;
};
